import{_ as r,C as i,o,c,a2 as t,b as d,w as s,a as n,E as l,a3 as u}from"./chunks/framework.DvFsUg-r.js";const D=JSON.parse('{"title":"블로그를 Docusaurus에서 VitePress로 — 블로그 없는 도구로 블로그 만들기","description":"","frontmatter":{"slug":"vitepress-migration","title":"블로그를 Docusaurus에서 VitePress로 — 블로그 없는 도구로 블로그 만들기","authors":[],"tags":["vitepress","docusaurus","migration","spec-kit","sdd","github-pages","mermaid"],"created":"2026-06-01 22:55 (KST)","date":"2026-06-01T13:55:00.000Z"},"headers":[],"relativePath":"journal/2026-06-01-vitepress-migration.md","filePath":"journal/2026-06-01-vitepress-migration.md","lastUpdated":1781092690000}'),p={name:"journal/2026-06-01-vitepress-migration.md"};function g(C,e,E,m,B,h){const a=i("Mermaid");return o(),c("div",null,[e[1]||(e[1]=t('<p>설계 저널 사이트(<code>blog/</code>)를 <strong>Docusaurus → VitePress</strong> 로 갈아엎었다. 참조 프로젝트(<code>youtube-do-not-build-agents</code>)와 같은 형태로 통일하고, MDX·React 의존이 만들던 빌드 취약성(특히 spec 동기화 때 <code>&lt;</code> 다음 숫자를 태그로 보던 사고)을 줄이는 게 목적이었다. feature 007 로 <strong>Spec Kit 한 바퀴</strong>를 돌렸고, 이 글은 그 과정의 기록이다.</p><h2 id="spec-kit-한-바퀴-—-이번엔-clarify가-두-번" tabindex="-1">Spec Kit 한 바퀴 — 이번엔 clarify가 두 번 <a class="header-anchor" href="#spec-kit-한-바퀴-—-이번엔-clarify가-두-번" aria-label="Permalink to &quot;Spec Kit 한 바퀴 — 이번엔 clarify가 두 번&quot;">​</a></h2><p>specify → clarify → plan → tasks → analyze → implement 를 한 세션에 돌렸다. 재미있던 건 <strong>clarify 가 결정한 것들</strong>이었다. &quot;VitePress 로 옮긴다&quot;는 한 줄 뒤에는 도구 차이에서 오는 진짜 결정들이 숨어 있었다.</p><ul><li><strong>VitePress엔 블로그 기능이 없다.</strong> Docusaurus 의 blog 플러그인 같은 게 없다. 그래서 저널 12편의 &quot;최근 먼저&quot; 목록을 어떻게 만들지가 곧 설계 문제가 됐다. → 빌드타임 <strong>data loader</strong>(<code>journal.data.mts</code>)로 frontmatter 를 읽어 <code>created</code> 내림차순 배열을 만들고, <code>journal/index.md</code> 가 그걸 렌더한다. 새 글을 추가하면 자동으로 맨 위에 붙는다(이 글처럼).</li><li><strong>사이드바가 수동이다.</strong> specs 가 늘 때마다 손으로 네비를 고치고 싶진 않았다. → 동기화 스크립트가 <code>specs/</code> 를 스캔해 <code>sidebar.specs.json</code> 을 <strong>feature 번호 내림차순</strong>으로 생성하고, config 가 그걸 import 한다.</li><li><strong>깨진 링크 정책.</strong> VitePress 는 기본이 strict(죽은 내부 링크 → 빌드 실패). 마침 우리가 원하던 CI 게이트라 기본값을 그대로 뒀다.</li><li><strong>테마는 참조 것 그대로.</strong> 갈색·세리프 &quot;퍼블리케이션&quot; 테마(<code>custom.css</code> 280줄)를 verbatim 으로 가져왔다.</li></ul><p>clarify 를 한 번 더 부른 건 마지막 질문 때문이었다 — &quot;참조의 <code>.vitepress/theme</code> 를 그대로 쓰는 거 맞지?&quot; plan/tasks 엔 &quot;claude.ai 톤 폰트로 새로 작성&quot;이라고 적혀 있어서 <strong>서로 충돌</strong>하던 걸 그때 잡았다. clarify 가 스펙뿐 아니라 plan·tasks 의 모순까지 끌어낸 셈.</p><h2 id="새-파이프라인" tabindex="-1">새 파이프라인 <a class="header-anchor" href="#새-파이프라인" aria-label="Permalink to &quot;새 파이프라인&quot;">​</a></h2>',6)),(o(),d(u,null,{default:s(()=>[l(a,{id:"mermaid-37",class:"mermaid",graph:"graph%20TD%0A%20%20specs%5B%22specs%2F**%2F*.md%20(%EB%8B%A8%EC%9D%BC%20%EC%B6%9C%EC%B2%98)%22%5D%20--%3E%7Csync%20%EC%8A%A4%ED%81%AC%EB%A6%BD%ED%8A%B8%7C%20gen%0A%20%20journal%5B%22blog%2Fjournal%2F*.md%22%5D%20--%3E%7Cdata%20loader%7C%20gen%0A%20%20subgraph%20build%5B%22VitePress%20%EB%B9%8C%EB%93%9C%20(strict)%22%5D%0A%20%20%20%20gen%5B%22%EC%BD%98%ED%85%90%EC%B8%A0%20%EC%A4%80%EB%B9%84%3Cbr%2F%3E%C2%B7%20specs%20%EB%B3%B5%EC%82%AC%3Cbr%2F%3E%C2%B7%20%EC%82%AC%EC%9D%B4%EB%93%9C%EB%B0%94%20%EC%9E%90%EB%8F%99%EC%83%9D%EC%84%B1%3Cbr%2F%3E%C2%B7%20%EC%A0%80%EB%84%90%20%EC%9D%B8%EB%8D%B1%EC%8A%A4%20%EC%9E%90%EB%8F%99%EC%83%9D%EC%84%B1%22%5D%20--%3E%20vp%5B%22vitepress%20build%22%5D%0A%20%20end%0A%20%20vp%20--%3E%20dist%5B%22dist%2F%20(base%3D%2Fblog%2F)%22%5D%0A%20%20dist%20--%3E%20pages%5B%22GitHub%20Pages%22%5D%0A"})]),fallback:s(()=>[...e[0]||(e[0]=[n(" Loading... ",-1)])]),_:1})),e[2]||(e[2]=t('<p>빌드 단계만 Docusaurus → VitePress 로 갈았고, &quot;main 푸시 → specs 동기화 → 빌드 → 배포&quot; 골격은 그대로 유지했다. <code>npm install</code> 한 번에 <strong>Docusaurus 패키지 1225개가 빠지고 80개가 들어왔다.</strong></p><h2 id="삽질·함정-로그" tabindex="-1">삽질·함정 로그 <a class="header-anchor" href="#삽질·함정-로그" aria-label="Permalink to &quot;삽질·함정 로그&quot;">​</a></h2><p>겉보기엔 &quot;도구 교체&quot;지만 콘텐츠 이관에서 몇 번 막혔다.</p><ol><li><strong>경로 실수.</strong> 첫 <code>package.json</code> 을 리포 루트(<code>D:\\ax\\blog</code>)에 써버렸다. 사이트는 <code>blog/</code> 하위인데. 바로 지우고 <code>blog/package.json</code> 으로 옮겼다.</li><li><strong>MDX 잔재.</strong> 저널 10편의 <code>{/* truncate */}</code> 주석을 걷어내고, vugrid 글의 <code>&lt;VuGrid&gt;</code> JSX 라이브 데모는 <strong>정적 표 + 명세 링크</strong>로 바꿨다(VitePress 는 MDX 가 아니라 JSX 컴포넌트를 못 그린다).</li><li><strong>dead-link의 거짓 양성.</strong> strict 빌드를 겁냈는데, 막상 돌리니 0건이었다. 본문 속 <code>/specs/...</code> 같은 <strong>인라인 코드</strong>는 링크가 아니라 그냥 텍스트라 검사 대상이 아니었다. 진짜 링크(<code>[...](/specs/docs-publishing-pipeline/spec)</code>) 몇 개만 번호 붙은 경로로 고쳐주면 됐다. — 옛 글 <a href="/journal/2026-05-31-spec-sync-mdx-pitfall">&quot;MDX는 <code>&lt;</code> 다음 숫자를 태그로 본다&quot;</a> 의 그 민감함이 VitePress 에선 없었다.</li><li><strong>react가 왜 lockfile에?</strong> docusaurus·react 를 다 걷어냈는데 lockfile 에 <code>react</code> 가 남아 있었다. 추적해 보니 VitePress 자신이 <code>@docsearch/js</code> 를 통해 옵셔널로 끌어오는 것(Algolia provider 용)이었다. 우리는 로컬 검색 (minisearch)이라 <strong>셸 사이트엔 React 가 번들되지 않는다.</strong> 표면적 grep 만 믿었으면 오판할 뻔했다.</li></ol><h2 id="헌법도-고쳤다" tabindex="-1">헌법도 고쳤다 <a class="header-anchor" href="#헌법도-고쳤다" aria-label="Permalink to &quot;헌법도 고쳤다&quot;">​</a></h2><p>프로젝트 헌법의 Tech Baseline 이 &quot;Docusaurus 3.10.x&quot; 로 박혀 있었다. 도구를 바꾸는 일이라 헌법 개정이 필요했고(<code>/speckit.analyze</code> 가 이걸 CRITICAL 로 잡아냈다), <strong>구현 착수 전에</strong> Tech Baseline 을 &quot;VitePress 1.6.x&quot; 로 올렸다 (v1.1.0 → 1.2.0). 코드보다 규칙이 먼저 정합을 맞춘 셈.</p><h2 id="마지막-—-전체폭-레이아웃" tabindex="-1">마지막 — 전체폭 레이아웃 <a class="header-anchor" href="#마지막-—-전체폭-레이아웃" aria-label="Permalink to &quot;마지막 — 전체폭 레이아웃&quot;">​</a></h2><p>이관 후 본문이 720px 좁은 컬럼(퍼블리케이션 테마 기본값)이라, <strong>메뉴와 목차는 고정폭으로 두고 본문만 전체폭</strong>으로 넓혔다. VitePress 1.6 의 실제 레이아웃 CSS 를 뜯어보니 본문 폭을 가두는 곳이 셋이었다 — <code>--vp-layout-max-width</code> (1440px 가운데 정렬), <code>.content-container</code>(688px), 그리고 우리 테마의 <code>.vp-doc</code>(720px). 셋만 풀고 사이드바(272px)·목차(256px)는 그대로 뒀다. 홈의 hero·features(1152px)도 같은 방식으로 넓혔다.</p><h2 id="남은-것" tabindex="-1">남은 것 <a class="header-anchor" href="#남은-것" aria-label="Permalink to &quot;남은 것&quot;">​</a></h2><ul><li>실제 배포 확인은 머지 후 GitHub Actions 에서. 로컬 strict 빌드는 깨진 링크 0건으로 통과한다.</li><li>vugrid 라이브 그리드는 접었다. 정적 표로 충분하지만, 스크린샷이 필요하면 <code>blog/public/img/</code> 에 넣을 자리만 만들어 뒀다.</li></ul><p>도구를 바꾸는 일은 늘 &quot;그대로 옮기기&quot;처럼 보이지만, 실제로는 <strong>그 도구가 없는 기능을 어떻게 메우느냐</strong>가 일의 절반이었다. 블로그 없는 도구로 블로그를 만드는 법 — data loader 와 sync 스크립트 두 개로 메웠다.</p>',11))])}const f=r(p,[["render",g]]);export{D as __pageData,f as default};
